# --- 安装函数 (由外部脚本运行) ---

# 主安装函数
_installer_secure_config_file() {
    if [ -f "$CONFIG_FILE" ]; then
        chmod 600 "$CONFIG_FILE" 2>/dev/null || true
    fi
}

_fuck_write_core() {
    local target="$1"
    printf '%s\n' "$CORE_LOGIC" > "$target"
    # 运行时替换版本占位符（安装时从 package.json 注入）
    if grep -q '__SCRIPT_VERSION__' "$target" 2>/dev/null; then
        local _pkg
        for _pkg in "$(dirname "$target")/../../package.json" "${_FC_SCRIPT_DIR:-}/../../package.json"; do
            if [ -f "$_pkg" ] && command -v node > /dev/null 2>&1; then
                local _ver
                _ver=$(node -e "console.log(require('$_pkg').version)" 2>/dev/null) || true
                if [ -n "$_ver" ]; then
                    sed -i.bak "s/__SCRIPT_VERSION__/${_ver}/g" "$target" && rm -f "${target}.bak"
                    break
                fi
            fi
        done
    fi
}

# 检查远程版本并与本地版本对比
_fuck_check_remote_version() {
    local api_url="${FUCK_API_ENDPOINT:-${DEFAULT_API_ENDPOINT:-https://fuckits.25500552.xyz/}}"
    local health_url="${api_url%/}/health"
    local remote_version
    remote_version=$(curl -sS --max-time 5 "$health_url" 2>/dev/null | grep -o '"version":"[^"]*"' | head -1 | sed 's/"version":"//;s/"//') || true

    if [ -z "$remote_version" ]; then
        return 0
    fi

    if [ "$remote_version" != "$SCRIPT_VERSION" ]; then
        echo -e "${C_YELLOW}📦 远程版本: ${C_BOLD}${remote_version}${C_RESET}${C_YELLOW} | 本地版本: ${C_BOLD}${SCRIPT_VERSION}${C_RESET}"
        echo -e "${C_CYAN}运行 'curl -sS ${api_url}/zh | bash' 以更新。${C_RESET}"
    else
        echo -e "${C_GREEN}✅ 版本 ${SCRIPT_VERSION} 已是最新。${C_RESET}"
    fi
}

# --- 初始化阶段独立版本（_install_script 依赖）---
# _fuck_source_core() 尚未运行，runtime-common.sh 不可用
_installer_detect_profile() {
    if [ -n "${SHELL:-}" ] && echo "$SHELL" | grep -q "zsh"; then
        echo "$HOME/.zshrc"
    elif [ -n "${SHELL:-}" ] && echo "$SHELL" | grep -q "bash"; then
        echo "$HOME/.bashrc"
    elif [ -f "$HOME/.profile" ]; then
        echo "$HOME/.profile"
    elif [ -f "$HOME/.zshrc" ]; then
        echo "$HOME/.zshrc"
    elif [ -f "$HOME/.bashrc" ]; then
        echo "$HOME/.bashrc"
    else
        echo "unknown_profile"
    fi
}

_install_script() {
    mkdir -p "$INSTALL_DIR"

    # 已安装时：先对比版本，相同则跳过更新
    if [ -f "$MAIN_SH" ]; then
        local local_ver
        local_ver=$(grep -o "SCRIPT_VERSION='[^']*'" "$MAIN_SH" 2>/dev/null | head -1 | sed "s/SCRIPT_VERSION='//;s/'//") || true

        local api_url="${FUCK_API_ENDPOINT:-${DEFAULT_API_ENDPOINT:-https://fuckits.25500552.xyz/}}"
        local remote_ver
        remote_ver=$(curl -sS --max-time 5 "${api_url%/}/health" 2>/dev/null | grep -o '"version":"[^"]*"' | head -1 | sed 's/"version":"//;s/"//') || true

        if [ -n "$local_ver" ] && [ -n "$remote_ver" ] && [ "$local_ver" = "$remote_ver" ]; then
            echo -e "${C_GREEN}✅ 版本 ${local_ver} 已是最新，无需更新。${C_RESET}"
            return 0
        fi

        if [ -n "$local_ver" ] && [ -n "$remote_ver" ]; then
            echo -e "${C_YELLOW}📦 本地版本: ${C_BOLD}${local_ver}${C_RESET}${C_YELLOW} → 远程版本: ${C_BOLD}${remote_ver}${C_RESET}"
            echo -e "${C_CYAN}正在更新...${C_RESET}"
        fi

        # 更新：删除旧脚本（保留配置和历史记录）
        rm -f "$MAIN_SH"
    fi

    echo -e "${C_BOLD}开始安装 fuckits...${C_RESET}"

    # 把核心逻辑写进 main.sh
    _fuck_write_core "$MAIN_SH"

    if [ $? -ne 0 ]; then
        echo -e "$FUCK ${C_RED}无法写入文件，请检查目录权限。${C_RESET}" >&2
        return 1
    fi

    # Make main.sh executable
    chmod +x "$MAIN_SH"

    # 如果没有配置文件则生成一个示例
    if [ ! -f "$CONFIG_FILE" ]; then
        cat <<'CFG' > "$CONFIG_FILE"
# fuckits 配置示例
# 去掉行首的 #，改成你自己的值即可。

# 自建/自定义 Worker 入口
# export FUCK_API_ENDPOINT="https://your-domain.workers.dev/"

# 本地 OpenAI 兼容 Key（强烈推荐）
# export FUCK_OPENAI_API_KEY="sk-..."

